def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        for n in range(1, 20):
            base = (1 / (n**3)) * (ratio ** n)
            if n % 4 == 0:
                base *= 1.4
            elif n % 5 == 0:
                base *= 1.2
            elif n % 2 == 0:
                base *= 1.1
            else:
                base *= 0.85
            if n % 7 == 0:
                base -= 0.007 * n
            score += base
        leftover = capacity - item
        if leftover < 0.02 * capacity:
            score *= 3.0
        elif leftover < 0.08 * capacity:
            score *= 1.8
        elif leftover < 0.15 * capacity:
            score *= 1.3
        elif leftover < 0.3 * capacity:
            score *= 0.95
        else:
            score *= 0.7
        cap_int = int(capacity)
        mods = [cap_int % i == 0 for i in (2,3,5,7,11)]
        if mods[0] and mods[2] and not mods[3]:
            score -= 0.14 * (capacity / 9)
        elif mods[1] and mods[3] and mods[4]:
            score -= 0.2 * (capacity / 13)
        elif mods[0] and mods[4]:
            score -= 0.1 * (capacity / 17)
        elif mods[2]:
            score -= 0.09 * (capacity / 25)
        elif mods[3]:
            score -= 0.07 * (capacity / 30)
        else:
            score -= 0.04 * (capacity / 40)
        penalty = 0.0
        for k in range(1, 8):
            close = abs(capacity - item * k)
            threshold1 = 0.012 * capacity * k
            threshold2 = 0.03 * capacity * k
            if close < threshold1:
                penalty += 0.3 * k
            elif close < threshold2:
                penalty += 0.15 * k
            elif close < 0.05 * capacity * k:
                penalty -= 0.1 * k
            else:
                penalty -= 0.07 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 6):
                val = capacity / m
                if abs(val - item) < 0.015 * val:
                    score *= (1 + 0.06 * m)
        complex_factor = 1.0
        for p in range(2, 6):
            if capacity % p == 0 and (item * p) < capacity * 1.1:
                complex_factor += 0.025 * p
            else:
                complex_factor -= 0.01 * p
        score *= max(0.5, complex_factor)
        priorities[idx] = score
    return priorities
